SELECT externalId, name FROM customers WHERE name LIKE '%Spicers Retreats%';

-- Check services for Spicers (any variant)
SELECT DISTINCT customerName, customerExternalId, externalId FROM services
WHERE customerName LIKE '%Spicers%' LIMIT 5;

